import API_ENDPOINTS from '../globals/api-endpoints';
import { success, fail } from '../utils/alert';

class RestoData {
  static async list() {
    success.showLoading();
    try {
      const response = await fetch(API_ENDPOINTS.LIST);
      const responseJson = await response.json();
      success.close();
      return responseJson.restaurants;
    } catch (error) {
      fail.fire({ text: error });
    }

  }

  static async details(id) {
    success.showLoading();
    try {
      const response = await fetch(API_ENDPOINTS.DETAILS(id));
      const responseJson = await response.json();
      success.close();
      return responseJson.restaurant;
    } catch (error) {
      fail.fire({ text: error });
    }
  }

  static async postReview(reviewData){
    success.showLoading();
    try {
      await fetch(API_ENDPOINTS.REVIEW, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(reviewData),
      });
      success.fire({ text: 'Restaurant Review has been posted.' });
    } catch (error) {
      fail.fire({ text: error });
    }
  }
}

export default RestoData;
